1243	// importScorecards imports scorecards grouped by blueprint.
1244	func (i *Importer) importScorecards(ctx context.Context, scorecards []api.Scorecard, result *Result, pool *WorkerPool) {
1245		byBlueprint := make(map[string][]api.Scorecard)
1246		for _, sc := range scorecards {
1247			bpID, ok1 := sc["blueprintIdentifier"].(string)
1248			scID, ok2 := sc["identifier"].(string)
1249			if !ok1 || !ok2 || bpID == "" || scID == "" {
1250				i.errors.Add(fmt.Errorf("scorecard is missing identifier or blueprintIdentifier field, skipping"), "scorecard", "<unknown>")
1251				continue
